SELECT * FROM t_expired_certificate
WHERE module_type = #{moduleType} AND module_id = #{moduleId} AND type = #{type}
LIMIT 1

SELECT * FROM t_expired_certificate


        enterprise_id = #{query.enterpriseId}


        module_type = #{query.moduleType}


        AND type = #{query.type}


        AND `status` = #{query.status}


        AND ( INSTR(module_name,#{query.searchWord}) )


        AND DATE_FORMAT(expired_time, '%Y-%m-%d') >= DATE_FORMAT(#{query.startDate}, '%Y-%m-%d')


        AND DATE_FORMAT(expired_time, '%Y-%m-%d') <= DATE_FORMAT(#{query.endDate}, '%Y-%m-%d')



    ORDER BY `status` ASC, expired_time ASC
